func aliasManagerXData(aliases []PageFormAliasView) string {
	if len(aliases) == 0 {
		return "aliasManager([])"
	}
	var parts []string
	for _, a := range aliases {
		parts = append(parts, fmt.Sprintf(`{value:'%s',id:%d}`, a.Alias, a.ID))
	}
	return fmt.Sprintf("aliasManager([%s])", strings.Join(parts, ","))
}

